class WalletManager {
    constructor() {
        this.wallets = new Map();
        this.providers = new Map();
    }

    /**
     * Initialize a provider for a given network
     */
    getProvider(networkName) {
        if (this.providers.has(networkName)) {
            return this.providers.get(networkName);
        }

        const rpcUrl = CONFIG.networks[networkName];
        if (!rpcUrl) {
            throw new Error(`Unknown network: ${networkName}`);
        }

        const provider = new ethers.JsonRpcProvider(rpcUrl);
        this.providers.set(networkName, provider);
        return provider;
    }

    /**
     * Load a wallet from private key
     * IMPORTANT: Private keys should ONLY come from environment variables or secure vaults
     * NEVER hardcode private keys in source code
     */
    loadWallet(walletName, privateKey, networkName = CONFIG.defaultNetwork) {
        if (!privateKey) {
            throw new Error(`Private key is required for wallet: ${walletName}`);
        }

        // Validate private key format
        if (!privateKey.startsWith('0x')) {
            privateKey = '0x' + privateKey;
        }

        if (privateKey.length !== 66) {
            throw new Error(`Invalid private key length for wallet: ${walletName}`);
        }

        const provider = this.getProvider(networkName);
        const wallet = new ethers.Wallet(privateKey, provider);

        this.wallets.set(walletName, {
            wallet,
            networkName,
            address: wallet.address
        });

        console.log(`Wallet '${walletName}' loaded: ${wallet.address} on ${networkName}`);
        return wallet.address;
    }

    /**
     * Load wallet from mnemonic phrase
     */
    loadWalletFromMnemonic(walletName, mnemonic, derivationPath = "m/44'/60'/0'/0/0", networkName = CONFIG.defaultNetwork) {
        const provider = this.getProvider(networkName);
        const hdNode = ethers.HDNodeWallet.fromPhrase(mnemonic, undefined, derivationPath);
        const wallet = hdNode.connect(provider);

        this.wallets.set(walletName, {
            wallet,
            networkName,
            address: wallet.address
        });

        console.log(`Wallet '${walletName}' loaded from mnemonic: ${wallet.address} on ${networkName}`);
        return wallet.address;
    }

    /**
     * Create a new random wallet
     */
    createRandomWallet(walletName, networkName = CONFIG.defaultNetwork) {
        const provider = this.getProvider(networkName);
        const randomWallet = ethers.Wallet.createRandom().connect(provider);

        this.wallets.set(walletName, {
            wallet: randomWallet,
            networkName,
            address: randomWallet.address
        });

        console.log(`New wallet '${walletName}' created: ${randomWallet.address}`);

        // Return address and encrypted private key info
        return {
            address: randomWallet.address,
            // In production, encrypt and store securely — never log private keys
            privateKey: randomWallet.privateKey
        };
    }

    /**
     * Get a loaded wallet by name
     */
    getWallet(walletName) {
        const entry = this.wallets.get(walletName);
        if (!entry) {
            throw new Error(`Wallet '${walletName}' not found. Load it first.`);
        }
        return entry.wallet;
    }

    /**
     * Get wallet address
     */
    getAddress(walletName) {
        const entry = this.wallets.get(walletName);
        if (!entry) {
            throw new Error(`Wallet '${walletName}' not found.`);
        }
        return entry.address;
    }

    /**
     * Get wallet balance
     */
    async getBalance(walletName) {
        const entry = this.wallets.get(walletName);
        if (!entry) {
            throw new Error(`Wallet '${walletName}' not found.`);
        }

        const balance = await entry.wallet.provider.getBalance(entry.address);
        return {
            wei: balance.toString(),
            ether: ethers.formatEther(balance)
        };
    }

    /**
     * List all loaded wallets
     */
    listWallets() {
        const walletList = [];
        for (const [name, entry] of this.wallets) {
            walletList.push({
                name,
                address: entry.address,
                network: entry.networkName
            });
        }
        return walletList;
    }
}

