class TransactionService {
    constructor(walletManager) {
        this.walletManager = walletManager;
    }

    /**
     * Send ETH from one wallet to a recipient address
     */
    async sendETH(fromWalletName, toAddress, amountInEther, options = {}) {
        const wallet = this.walletManager.getWallet(fromWalletName);

        // Validate recipient address
        if (!ethers.isAddress(toAddress)) {
            throw new Error(`Invalid recipient address: ${toAddress}`);
        }

        const amountWei = ethers.parseEther(amountInEther.toString());

        // Check balance
        const balance = await wallet.provider.getBalance(wallet.address);
        if (balance < amountWei) {
            throw new Error(
                `Insufficient balance. Have: ${ethers.formatEther(balance)} ETH, Need: ${amountInEther} ETH`
            );
        }

        // Build transaction
        const tx = {
            to: toAddress,
            value: amountWei,
            gasLimit: options.gasLimit || CONFIG.gas.gasLimit
        };

        // Optionally set gas price parameters
        if (options.maxFeePerGas) {
            tx.maxFeePerGas = ethers.parseUnits(options.maxFeePerGas.toString(), 'gwei');
            tx.maxPriorityFeePerGas = ethers.parseUnits(
                (options.maxPriorityFeePerGas || 2).toString(), 'gwei'
            );
        }

        // Add nonce if specified (useful for transaction replacement)
        if (options.nonce !== undefined) {
            tx.nonce = options.nonce;
        }

        console.log(`Sending ${amountInEther} ETH from ${wallet.address} to ${toAddress}...`);

        // Sign and send transaction
        const txResponse = await wallet.sendTransaction(tx);
        console.log(`Transaction sent! Hash: ${txResponse.hash}`);

        // Wait for confirmation if requested
        if (options.waitConfirmations) {
            console.log(`Waiting for ${options.waitConfirmations} confirmation(s)...`);
            const receipt = await txResponse.wait(options.waitConfirmations);
            console.log(`Transaction confirmed in block ${receipt.blockNumber}`);
            return {
                hash: txResponse.hash,
                receipt,
                status: receipt.status === 1 ? 'success' : 'failed'
            };
        }

        return {
            hash: txResponse.hash,
            txResponse
        };
    }

    /**
     * Send a batch of ETH transactions
     */
    async sendBatchETH(fromWalletName, transfers, options = {}) {
        const wallet = this.walletManager.getWallet(fromWalletName);
        let nonce = await wallet.provider.getTransactionCount(wallet.address, 'latest');

        const results = [];

        for (const transfer of transfers) {
            try {
                const result = await this.sendETH(fromWalletName, transfer.to, transfer.amount, {
                    ...options,
                    nonce: nonce++
                });
                results.push({ ...transfer, ...result, status: 'sent' });
            } catch (error) {
                results.push({ ...transfer, status: 'failed', error: error.message });
                // If nonce was consumed, don't increment; if not, decrement
                nonce--;
            }
        }

        return results;
    }

    /**
     * Get transaction receipt
     */
    async getTransactionReceipt(txHash, networkName = CONFIG.defaultNetwork) {
        const provider = this.walletManager.getProvider(networkName);
        const receipt = await provider.getTransactionReceipt(txHash);
        if (!receipt) {
            return { status: 'pending', hash: txHash };
        }
        return {
            status: receipt.status === 1 ? 'success' : 'failed',
            hash: txHash,
            blockNumber: receipt.blockNumber,
            gasUsed: receipt.gasUsed.toString(),
            from: receipt.from,
            to: receipt.to
        };
    }

    /**
     * Estimate gas for a transaction
     */
    async estimateGas(fromWalletName, toAddress, amountInEther, data = '0x') {
        const wallet = this.walletManager.getWallet(fromWalletName);

        const tx = {
            from: wallet.address,
            to: toAddress,
            value: ethers.parseEther(amountInEther.toString()),
            data
        };

        const gasEstimate = await wallet.provider.estimateGas(tx);
        const feeData = await wallet.provider.getFeeData();

        return {
            gasLimit: gasEstimate.toString(),
            maxFeePerGas: feeData.maxFeePerGas ? ethers.formatUnits(feeData.maxFeePerGas, 'gwei') + ' gwei' : 'N/A',
            maxPriorityFeePerGas: feeData.maxPriorityFeePerGas ? ethers.formatUnits(feeData.maxPriorityFeePerGas, 'gwei') + ' gwei' : 'N/A',
            gasPrice: feeData.gasPrice ? ethers.formatUnits(feeData.gasPrice, 'gwei') + ' gwei' : 'N/A'
        };
    }
}

