class SmartContractService {
    constructor(walletManager) {
        this.walletManager = walletManager;
        this.contracts = new Map();
    }

    /**
     * Load a smart contract instance
     */
    loadContract(contractName, contractAddress, abi, walletName = null) {
        if (!ethers.isAddress(contractAddress)) {
            throw new Error(`Invalid contract address: ${contractAddress}`);
        }

        let signerOrProvider;
        if (walletName) {
            signerOrProvider = this.walletManager.getWallet(walletName);
        } else {
            signerOrProvider = this.walletManager.getProvider(CONFIG.defaultNetwork);
        }

        const contract = new ethers.Contract(contractAddress, abi, signerOrProvider);

        this.contracts.set(contractName, {
            contract,
            address: contractAddress,
            walletName
        });

        console.log(`Contract '${contractName}' loaded at ${contractAddress}`);
        return contract;
    }

    /**
     * Get a loaded contract
     */
    getContract(contractName) {
        const entry = this.contracts.get(contractName);
        if (!entry) {
            throw new Error(`Contract '${contractName}' not found. Load it first.`);
        }
        return entry.contract;
    }

    /**
     * Call a read-only (view/pure) function on a contract
     */
    async callReadFunction(contractName, functionName, ...args) {
        const contract = this.getContract(contractName);

        if (!contract[functionName]) {
            throw new Error(`Function '${functionName}' not found on contract '${contractName}'`);
        }

        console.log(`Calling ${contractName}.${functionName}(${args.join(', ')})...`);
        const result = await contract[functionName](...args);
        return result;
    }

    /**
     * Send a write transaction to a contract
     */
    async callWriteFunction(contractName, functionName, args = [], options = {}) {
        const contract = this.getContract(contractName);

        if (!contract[functionName]) {
            throw new Error(`Function '${functionName}' not found on contract '${contractName}'`);
        }

        // Build overrides
        const overrides = {};
        if (options.value) {
            overrides.value = ethers.parseEther(options.value.toString());
        }
        if (options.gasLimit) {
            overrides.gasLimit = options.gasLimit;
        }
        if (options.maxFeePerGas) {
            overrides.maxFeePerGas = ethers.parseUnits(options.maxFeePerGas.toString(), 'gwei');
        }
        if (options.maxPriorityFeePerGas) {
            overrides.maxPriorityFeePerGas = ethers.parseUnits(options.maxPriorityFeePerGas.toString(), 'gwei');
        }
        if (options.nonce !== undefined) {
            overrides.nonce = options.nonce;
        }

        console.log(`Sending tx: ${contractName}.${functionName}(${args.join(', ')})...`);

        const txArgs = [...args];
        if (Object.keys(overrides).length > 0) {
            txArgs.push(overrides);
        }

        const txResponse = await contract[functionName](...txArgs);
        console.log(`Transaction sent! Hash: ${txResponse.hash}`);

        if (options.waitConfirmations) {
            console.log(`Waiting for ${options.waitConfirmations} confirmation(s)...`);
            const receipt = await txResponse.wait(options.waitConfirmations);
            console.log(`Transaction confirmed in block ${receipt.blockNumber}`);
            return {
                hash: txResponse.hash,
                receipt,
                status: receipt.status === 1 ? 'success' : 'failed',
                events: receipt.logs
            };
        }

        return {
            hash: txResponse.hash,
            txResponse
        };
    }

    /**
     * Deploy a new smart contract
     */
    async deployContract(walletName, abi, bytecode, constructorArgs = [], options = {}) {
        const wallet = this.walletManager.getWallet(walletName);

        const factory = new ethers.ContractFactory(abi, bytecode, wallet);

        console.log(`Deploying contract from ${wallet.address}...`);

        const overrides = {};
        if (options.gasLimit) overrides.gasLimit = options.gasLimit;
        if (options.value) overrides.value = ethers.parseEther(options.value.toString());

        const deployArgs = [...constructorArgs];
        if (Object.keys(overrides).length > 0) {
            deployArgs.push(overrides);
        }

        const contract = await factory.deploy(...deployArgs);
        console.log(`Contract deployment tx: ${contract.deploymentTransaction().hash}`);

        // Wait for deployment
        await contract.waitForDeployment();
        const deployedAddress = await contract.getAddress();
        console.log(`Contract deployed at: ${deployedAddress}`);

        return {
            contract,
            address: deployedAddress,
            deploymentTx: contract.deploymentTransaction().hash
        };
    }

    /**
     * Listen to contract events
     */
    listenToEvent(contractName, eventName, callback) {
        const contract = this.getContract(contractName);

        contract.on(eventName, (...args) => {
            const event = args[args.length - 1]; // Last arg is the event object
            console.log(`Event '${eventName}' from '${contractName}'`);
            callback(...args);
        });

        console.log(`Listening for '${eventName}' events on '${contractName}'`);
    }

    /**
     * Query past events
     */
    async queryEvents(contractName, eventName, fromBlock = 0, toBlock = 'latest') {
        const contract = this.getContract(contractName);
        const filter = contract.filters[eventName]();
        const events = await contract.queryFilter(filter, fromBlock, toBlock);
        return events.map(event => ({
            blockNumber: event.blockNumber,
            transactionHash: event.transactionHash,
            args: event.args,
            eventName: event.eventName || event.fragment?.name
        }));
    }

    /**
     * Encode function call data (useful for multi-sig or meta transactions)
     */
    encodeFunctionData(contractName, functionName, args = []) {
        const contract = this.getContract(contractName);
        return contract.interface.encodeFunctionData(functionName, args);
    }

    /**
     * Decode function result
     */
    decodeFunctionResult(contractName, functionName, data) {
        const contract = this.getContract(contractName);
        return contract.interface.decodeFunctionResult(functionName, data);
    }
}

// =============================================================================
// ERC20 TOKEN SERVICE (Common Use Case)
// =============================================================================

const ERC20_ABI = [
    'function name() view returns (string)',
    'function symbol() view returns (string)',
    'function decimals() view returns (uint8)',
    'function totalSupply() view returns (uint256)',
    'function balanceOf(address owner) view returns (uint256)',
    'function transfer(address to, uint256 amount) returns (bool)',
    'function approve(address spender, uint256 amount) returns (bool)',
    'function allowance(address owner, address spender) view returns (uint256)',
    'function transferFrom(address from, address to, uint256 amount) returns (bool)',
    'event Transfer(address indexed from, address indexed to, uint256 value)',
    'event Approval(address indexed owner, address indexed spender, uint256 value)'
];

class ERC20Service {
    constructor(walletManager) {
        this.walletManager = walletManager;
        this.tokens = new Map();
    }

    /**
     * Load an ERC20 token
     */
    loadToken(tokenName, tokenAddress, walletName) {
        const wallet = this.walletManager.getWallet(walletName);
        const contract = new ethers.Contract(tokenAddress, ERC20_ABI, wallet);

        this.tokens.set(tokenName, {
            contract,
            address: tokenAddress,
            walletName
        });

        console.log(`ERC20 Token '${tokenName}' loaded at ${tokenAddress}`);
        return contract;
    }

    /**
     * Get token info
     */
    async getTokenInfo(tokenName) {
        const { contract } = this.tokens.get(tokenName);
        const [name, symbol, decimals, totalSupply] = await Promise.all([
            contract.name(),
            contract.symbol(),
            contract.decimals(),
            contract.totalSupply()
        ]);

        return {
            name,
            symbol,
            decimals: Number(decimals),
            totalSupply: ethers.formatUnits(totalSupply, decimals),
            address: contract.target
        };
    }

    /**
     * Get token balance for an address
     */
    async getBalance(tokenName, address) {
        const { contract } = this.tokens.get(tokenName);
        const decimals = await contract.decimals();
        const balance = await contract.balanceOf(address);
        return {
            raw: balance.toString(),
            formatted: ethers.formatUnits(balance, decimals)
        };
    }

    /**
     * Transfer tokens
     */
    async transfer(tokenName, toAddress, amount, options = {}) {
        const { contract } = this.tokens.get(tokenName);
        const decimals = await contract.decimals();
        const amountWei = ethers.parseUnits(amount.toString(), decimals);

        console.log(`Transferring ${amount} ${tokenName} to ${toAddress}...`);

        const tx = await contract.transfer(toAddress, amountWei);
        console.log(`Transfer tx: ${tx.hash}`);

        if (options.waitConfirmations) {
            const receipt = await tx.wait(options.waitConfirmations);
            return {
                hash: tx.hash,
                receipt,
                status: receipt.status === 1 ? 'success' : 'failed'
            };
        }

        return { hash: tx.hash, txResponse: tx };
    }

    /**
     * Approve token spending
     */
    async approve(tokenName, spenderAddress, amount, options = {}) {
        const { contract } = this.tokens.get(tokenName);
        const decimals = await contract.decimals();
        const amountWei = ethers.parseUnits(amount.toString(), decimals);

        console.log(`Approving ${amount} ${tokenName} for ${spenderAddress}...`);

        const tx = await contract.approve(spenderAddress, amountWei);
        console.log(`Approval tx: ${tx.hash}`);

        if (options.waitConfirmations) {
            const receipt = await tx.wait(options.waitConfirmations);
            return {
                hash: tx.hash,
                receipt,
                status: receipt.status === 1 ? 'success' : 'failed'
            };
        }

        return { hash: tx.hash, txResponse: tx };
    }

    /**
     * Check allowance
     */
    async getAllowance(tokenName, ownerAddress, spenderAddress) {
        const { contract } = this.tokens.get(tokenName);
        const decimals = await contract.decimals();
        const allowance = await contract.allowance(ownerAddress, spenderAddress);
        return {
            raw: allowance.toString(),
            formatted: ethers.formatUnits(allowance, decimals)
        };
    }

    /**
     * Listen for Transfer events
     */
    onTransfer(tokenName, callback) {
        const { contract } = this.tokens.get(tokenName);
        contract.on('Transfer', (from, to, value, event) => {
            callback({ from, to, value: value.toString(), event });
        });
        console.log(`Listening for Transfer events on ${tokenName}`);
    }
}

