class UtilityService {
    constructor(walletManager) {
        this.walletManager = walletManager;
    }

    /**
     * Get current block number
     */
    async getBlockNumber(networkName = CONFIG.defaultNetwork) {
        const provider = this.walletManager.getProvider(networkName);
        return await provider.getBlockNumber();
    }

    /**
     * Get block details
     */
    async getBlock(blockNumber, networkName = CONFIG.defaultNetwork) {
        const provider = this.walletManager.getProvider(networkName);
        return await provider.getBlock(blockNumber);
    }

    /**
     * Get current gas price
     */
    async getGasPrice(networkName = CONFIG.defaultNetwork) {
        const provider = this.walletManager.getProvider(networkName);
        const feeData = await provider.getFeeData();
        return {
            gasPrice: feeData.gasPrice ? ethers.formatUnits(feeData.gasPrice, 'gwei') + ' gwei' : 'N/A',
            maxFeePerGas: feeData.maxFeePerGas ? ethers.formatUnits(feeData.maxFeePerGas, 'gwei') + ' gwei' : 'N/A',
            maxPriorityFeePerGas: feeData.maxPriorityFeePerGas ? ethers.formatUnits(feeData.maxPriorityFeePerGas, 'gwei') + ' gwei' : 'N/A'
        };
    }

    /**
     * Get the ETH balance of any address (no wallet needed)
     */
    async getAddressBalance(address, networkName = CONFIG.defaultNetwork) {
        const provider = this.walletManager.getProvider(networkName);
        const balance = await provider.getBalance(address);
        return {
            wei: balance.toString(),
            ether: ethers.formatEther(balance)
        };
    }

    /**
     * Get transaction count (nonce) for an address
     */
    async getNonce(address, networkName = CONFIG.defaultNetwork) {
        const provider = this.walletManager.getProvider(networkName);
        return await provider.getTransactionCount(address, 'latest');
    }

    /**
     * Resolve ENS name to address
     */
    async resolveENS(ensName, networkName = 'mainnet') {
        const provider = this.walletManager.getProvider(networkName);
        return await provider.resolveName(ensName);
    }

    /**
     * Sign a message
     */
    async signMessage(walletName, message) {
        const wallet = this.walletManager.getWallet(walletName);
        const signature = await wallet.signMessage(message);
        return {
            message,
            signature,
            signer: wallet.address
        };
    }

    /**
     * Verify a signed message
     */
    verifyMessage(message, signature) {
        const recoveredAddress = ethers.verifyMessage(message, signature);
        return recoveredAddress;
    }

    /**
     * Sign typed data (EIP-712)
     */
    async signTypedData(walletName, domain, types, value) {
        const wallet = this.walletManager.getWallet(walletName);
        const signature = await wallet.signTypedData(domain, types, value);
        return {
            signature,
            signer: wallet.address
        };
    }

    /**
     * Watch for pending transactions to an address
     */
    async watchPendingTransactions(address, callback, networkName = CONFIG.defaultNetwork) {
        const provider = this.walletManager.getProvider(networkName);

        provider.on('pending', async (txHash) => {
            try {
                const tx = await provider.getTransaction(txHash);
                if (tx && (tx.to === address || tx.from === address)) {
                    callback(tx);
                }
            } catch (e) {
                // Transaction may have been mined already
            }
        });

        console.log(`Watching pending transactions for ${address}`);
    }
}

