class DAppBackendService {
    constructor() {
        this.walletManager = new WalletManager();
        this.transactionService = new TransactionService(this.walletManager);
        this.contractService = new SmartContractService(this.walletManager);
        this.erc20Service = new ERC20Service(this.walletManager);
        this.utilityService = new UtilityService(this.walletManager);
    }

    /**
     * Initialize the service with wallets from environment variables
     */
    initialize() {
        // Load wallets from environment variables
        // NEVER hardcode private keys — use .env file or secret management
        if (process.env.DEPLOYER_PRIVATE_KEY) {
            this.walletManager.loadWallet('deployer', process.env.DEPLOYER_PRIVATE_KEY);
        }

        if (process.env.OPERATOR_PRIVATE_KEY) {
            this.walletManager.loadWallet('operator', process.env.OPERATOR_PRIVATE_KEY);
        }

        if (process.env.TREASURY_PRIVATE_KEY) {
            this.walletManager.loadWallet('treasury', process.env.TREASURY_PRIVATE_KEY);
        }

        console.log('DApp Backend Service initialized');
        console.log('Loaded wallets:', this.walletManager.listWallets());
    }
}

